const customFields = $('Get Custom Field Names').first().json.data;
const matterFields = $('Get Matter Field Value IDs').first().json.data.custom_field_values;

// Build a map of custom_field id -> name
const nameMap = {};
for (const field of customFields) {
  nameMap[field.id] = field.name;
}

// Build output mapping
const result = {};
for (const val of matterFields) {
  const cfId = val.custom_field.id;
  const name = nameMap[cfId] || `unknown_${cfId}`;
  result[name] = {
    custom_field_value_id: val.id,
    custom_field_id: cfId,
    current_value: val.value
  };
}

return [{ json: result }];

